//! The maze can be generated with [`maze_gen.py`](../maze_gen.py)
//! By default I use a 31x31 maze, but have fun with the 100x100 too

use libafl_ijon::ijon_set;

/// Target to fuzzz
pub fn maze(input: &[u8]) {
    // starting position
    let mut pos: (usize, usize) = (15, 15);

    // counter for printing
    // let mut counter = 0;

    for &byte in input {
        // counter += 1;

        let next_pos = match byte % 4 {
            0 => (pos.0.wrapping_sub(1), pos.1), // up
            1 => (pos.0 + 1, pos.1),             // down
            2 => (pos.0, pos.1.wrapping_sub(1)), // left
            _ => (pos.0, pos.1 + 1),             // right
        };

        if next_pos.0 < 31 && next_pos.1 < 31 && MAZE[next_pos.0][next_pos.1] != 1 {
            pos = next_pos;
        }

        // println!("Location: move={} row={} col={}", counter, pos.0, pos.1);

        // crash when exit is reached
        if MAZE[pos.0][pos.1] == 3 {
            panic!("Escaped! :)");
        }

        ijon_set!(pos);
    }
}

